using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<Person> directly (no cast needed)
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
var json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"Serialized with typed metadata: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
//    Person is resolvable (reflection resolver handles any type):
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
    Console.WriteLine($"TryGet succeeded for {info!.Type.Name}");
else
    Console.WriteLine("TryGet failed for Person");

// Now use a source-gen context that only knows about Person.
// Querying for int[] will return false instead of throwing.
var limited = new JsonSerializerOptions { TypeInfoResolver = SmallContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
    Console.WriteLine($"TryGet succeeded for {arrayInfo!.Type.Name}");
else
    Console.WriteLine("TryGet failed for int[] — metadata not available (no exception!)");

// ------- types -------
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class SmallContext : JsonSerializerContext;

